export interface ApiMembership {
  id: string;
  referenceId: string;
  referenceType: string;
  role: string;
  source: string;
  sourceId: string;
  user: {
    id: string;
    displayName: string;
    email: string;
  };
}

export function isValidMembership(membership: ApiMembership): boolean {
  return (
    membership.id !== undefined &&
    membership.referenceId !== undefined &&
    membership.referenceType !== undefined &&
    membership.role !== undefined &&
    membership.source !== undefined &&
    membership.sourceId !== undefined &&
    membership.user !== undefined
  );
}
